mapper.select:
SELECT a.id, a.company_id as "companyId", a.applicant_id as "applicantId", b.name as "applicantName", a.leave_type as "leaveType", a.duration, a.reason, a.attachments, a.status,
DATE_FORMAT(a.start_time, '%Y-%m-%d %H:%i:%s') AS "startTime", DATE_FORMAT(a.end_time, '%Y-%m-%d %H:%i:%s') AS "endTime", DATE_FORMAT(a.submit_time, '%Y-%m-%d %H:%i:%s') AS "submitTime", DATE_FORMAT(a.created_at, '%Y-%m-%d %H:%i:%s') AS "createdAt"
to_char(a.start_time,'yyyy-MM-dd HH24:MI:ss') AS "startTime", to_char(a.end_time,'yyyy-MM-dd HH24:MI:ss') AS "endTime", to_char(a.submit_time,'yyyy-MM-dd HH24:MI:ss') AS "submitTime", to_char(a.created_at,'yyyy-MM-dd HH24:MI:ss') AS "createdAt"
to_char(a.start_time,'yyyy-MM-dd HH24:MI:ss') AS "startTime", to_char(a.end_time,'yyyy-MM-dd HH24:MI:ss') AS "endTime", to_char(a.submit_time,'yyyy-MM-dd HH24:MI:ss') AS "submitTime", to_char(a.created_at,'yyyy-MM-dd HH24:MI:ss') AS "createdAt"
to_char(a.start_time,'yyyy-MM-dd HH24:MI:ss') AS "startTime", to_char(a.end_time,'yyyy-MM-dd HH24:MI:ss') AS "endTime", to_char(a.submit_time,'yyyy-MM-dd HH24:MI:ss') AS "submitTime", to_char(a.created_at,'yyyy-MM-dd HH24:MI:ss') AS "createdAt"
to_char(a.start_time,'yyyy-MM-dd HH24:MI:ss') AS "startTime", to_char(a.end_time,'yyyy-MM-dd HH24:MI:ss') AS "endTime", to_char(a.submit_time,'yyyy-MM-dd HH24:MI:ss') AS "submitTime", to_char(a.created_at,'yyyy-MM-dd HH24:MI:ss') AS "createdAt"
CONVERT(varchar, a.start_time, 120 ) AS "startTime", CONVERT(varchar, a.end_time, 120 ) AS "endTime", CONVERT(varchar, a.submit_time, 120 ) AS "submitTime", CONVERT(varchar, a.created_at, 120 ) AS "createdAt"
FROM leave_request a LEFT JOIN sys_account b ON b.id = a.applicant_id
a.company_id = #{companyId}
AND a.applicant_id = #{applicantId}
AND b.name LIKE CONCAT('%', #{applicantName}, '%')
AND b.name LIKE '%' || #{applicantName} || '%'
AND b.name LIKE '%' || #{applicantName} || '%'
AND b.name LIKE '%' || #{applicantName} || '%'
AND b.name LIKE '%' || #{applicantName} || '%'
AND b.name LIKE '%' + #{applicantName} + '%'
AND a.leave_type = #{leaveType}
AND a.status = #{status}
AND DATE_FORMAT(a.start_time, '%Y-%m-%d %H:%i:%s') between #{startTime} and #{endTime}
AND to_char(a.start_time,'yyyy-MM-dd HH24:MI:ss') between #{startTime} and #{endTime}
AND to_char(a.start_time,'yyyy-MM-dd HH24:MI:ss') between #{startTime} and #{endTime}
AND to_char(a.start_time,'yyyy-MM-dd HH24:MI:ss') between #{startTime} and #{endTime}
AND to_char(a.start_time,'yyyy-MM-dd HH24:MI:ss') between #{startTime} and #{endTime}
AND CONVERT(varchar, a.start_time, 120 ) between #{startTime} and #{endTime}
ORDER BY a.created_at DESC
